      "entity_name": "Business Continuity and Disaster Recovery Plan",
      "properties": {
        "policy_owner": "VP of Engineering",
        "effective_date": "01/01/2025",
        "purpose": "To ensure the continuity of Tellius's critical business functions and the recovery of its IT infrastructure in the event of disruptions."
      }
    },
