      "entity_id": "9",
      "entity_type": "policy",
      "entity_name": "Information Security Policy",
      "properties": {
        "policy_owner": "VP of Engineering",
        "effective_date": "01/01/2025",
        "purpose": "To protect Tellius, Inc.'s employees, partners and the company from illegal or damaging actions."
      }
    },
    {
      "entity_id": "10",
      "entity_type": "policy",
      "entity_name": "Operations Security Policy",
      "properties": {
        "policy_owner": "Operations Lead",
