      "entity_type": "policy",
      "entity_name": "Physical Security Policy",
      "properties": {
        "policy_owner": "Operations Lead",
        "effective_date": "06/01/2021",
        "purpose": "To prevent unauthorized physical access or damage to the organization\u2019s information and information processing facilities."
      }
    },
    {
      "entity_id": "12",
      "entity_type": "policy",
      "entity_name": "Risk Management Policy",
      "properties": {
        "policy_owner": "VP of Engineering",
        "effective_date": "01/01/2025",
        "purpose": "To define the process for assessing and managing Tellius, Inc.'s information security risks."
      }
    },
    {
      "entity_id": "13",
      "entity_type": "policy",
      "entity_name": "Third-Party Management Policy",
